/* resources.js — assets inlined as data URIs so the page renders even if the
   assets/ folder is missing or mis-uploaded (e.g. on static hosts / GitHub Pages).
   The components read window.__resources first, then fall back to assets/ paths. */
window.__resources = {"navLogo":"data:image/svg+xml;base64,","footerLogo":"data:image/svg+xml;base64,","coinBadge":"data:image/png;base64,"};
